/**
 * Competitor Opportunities Page — Shows confirmed competitor insights.
 *
 * Displays competitor comparison cards with:
 * - Competitor name, strength, weakness, opportunity, suggested action
 * - Only shows type === 'competitor' and reviewStatus === 'confirmed'
 */

import React, { useEffect, useMemo } from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  Chip,
  Grid,
  Avatar,
} from '@mui/material';
import TrendingUpIcon from '@mui/icons-material/TrendingUp';
import ArrowUpwardIcon from '@mui/icons-material/ArrowUpward';
import ArrowDownwardIcon from '@mui/icons-material/ArrowDownward';
import EmojiObjectsIcon from '@mui/icons-material/EmojiObjects';
import { useBrandStore } from '@/shared/stores/brandStore';
import { useInsightStore } from '@/shared/stores/insightStore';
import type { CompetitorInsight } from '@/shared/types/insight';

const AVATAR_COLORS = ['#6366f1', '#ec4899', '#14b8a6', '#f59e0b', '#8b5cf6', '#06b6d4'];

const CompetitorPage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const brand = useBrandStore((s) => s.getCurrentBrand());
  const insights = useInsightStore((s) => s.insights);
  const loadInsights = useInsightStore((s) => s.loadInsights);

  const brandId = currentBrandId ?? '';

  useEffect(() => {
    if (brandId) loadInsights(brandId);
  }, [brandId, loadInsights]);

  // Filter: only confirmed competitor insights
  const competitors = useMemo(
    () =>
      insights.filter(
        (i) => i.type === 'competitor' && i.reviewStatus === 'confirmed',
      ) as CompetitorInsight[],
    [insights],
  );

  // Group by competitor name
  const grouped = useMemo(() => {
    const map = new Map<string, CompetitorInsight[]>();
    competitors.forEach((c) => {
      const existing = map.get(c.competitorName) ?? [];
      existing.push(c);
      map.set(c.competitorName, existing);
    });
    return Array.from(map.entries());
  }, [competitors]);

  return (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      {/* Header */}
      <Box
        sx={{
          p: 2,
          borderBottom: '1px solid',
          borderColor: 'divider',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
        }}
      >
        <Box>
          <Typography variant="h6" fontWeight={700}>
            🎯 竞品机会
          </Typography>
          <Typography variant="body2" color="text.secondary">
            {brand?.name ?? ''} · 已确认竞品洞察 {competitors.length} 条
          </Typography>
        </Box>
      </Box>

      {/* Content */}
      <Box sx={{ flex: 1, overflow: 'auto', p: 2 }}>
        {grouped.length === 0 ? (
          <Box
            sx={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              height: '100%',
              gap: 2,
            }}
          >
            <TrendingUpIcon sx={{ fontSize: 48, color: 'text.disabled' }} />
            <Typography variant="body1" color="text.secondary">
              暂无已确认的竞品洞察
            </Typography>
            <Typography variant="caption" color="text.disabled">
              请先在 AI 工作台运行分析，然后在审核工作台确认洞察
            </Typography>
          </Box>
        ) : (
          <Grid container spacing={2}>
            {grouped.map(([compName, items], groupIdx) => (
              <Grid item xs={12} key={compName}>
                {/* Competitor header */}
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, mb: 1.5 }}>
                  <Avatar
                    sx={{
                      bgcolor: AVATAR_COLORS[groupIdx % AVATAR_COLORS.length],
                      width: 36,
                      height: 36,
                      fontSize: 16,
                      fontWeight: 700,
                    }}
                  >
                    {compName.charAt(0)}
                  </Avatar>
                  <Typography variant="subtitle1" fontWeight={700}>
                    {compName}
                  </Typography>
                  <Chip label={`${items.length} 条洞察`} size="small" variant="outlined" />
                </Box>

                <Grid container spacing={2}>
                  {items.map((item) => (
                    <Grid item xs={12} sm={6} md={4} key={item.id}>
                      <Card
                        sx={{
                          height: '100%',
                          display: 'flex',
                          flexDirection: 'column',
                        }}
                      >
                        <CardContent sx={{ flex: 1 }}>
                          {/* Strength / Weakness */}
                          <Box sx={{ display: 'flex', gap: 1, mb: 1.5 }}>
                            <Box
                              sx={{
                                flex: 1,
                                p: 1,
                                borderRadius: 1,
                                bgcolor: 'success.50',
                                border: '1px solid',
                                borderColor: 'success.100',
                              }}
                            >
                              <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, mb: 0.25 }}>
                                <ArrowUpwardIcon sx={{ fontSize: 14, color: 'success.main' }} />
                                <Typography variant="caption" fontWeight={600} color="success.main">
                                  优势
                                </Typography>
                              </Box>
                              <Typography variant="caption" color="text.secondary">
                                {item.strength}
                              </Typography>
                            </Box>
                            <Box
                              sx={{
                                flex: 1,
                                p: 1,
                                borderRadius: 1,
                                bgcolor: 'error.50',
                                border: '1px solid',
                                borderColor: 'error.100',
                              }}
                            >
                              <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, mb: 0.25 }}>
                                <ArrowDownwardIcon sx={{ fontSize: 14, color: 'error.main' }} />
                                <Typography variant="caption" fontWeight={600} color="error.main">
                                  劣势
                                </Typography>
                              </Box>
                              <Typography variant="caption" color="text.secondary">
                                {item.weakness}
                              </Typography>
                            </Box>
                          </Box>

                          {/* Opportunity */}
                          <Box
                            sx={{
                              p: 1,
                              borderRadius: 1,
                              bgcolor: 'info.50',
                              border: '1px solid',
                              borderColor: 'info.100',
                              mb: 1,
                            }}
                          >
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, mb: 0.25 }}>
                              <EmojiObjectsIcon sx={{ fontSize: 14, color: 'info.main' }} />
                              <Typography variant="caption" fontWeight={600} color="info.main">
                                我方机会
                              </Typography>
                            </Box>
                            <Typography variant="caption" color="text.secondary">
                              {item.opportunity}
                            </Typography>
                          </Box>

                          {/* Action */}
                          {item.action && (
                            <Box
                              sx={{
                                p: 1,
                                borderRadius: 1,
                                bgcolor: 'action.hover',
                              }}
                            >
                              <Typography variant="caption" fontWeight={600} color="text.secondary">
                                🎯 建议动作
                              </Typography>
                              <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mt: 0.25 }}>
                                {item.action}
                              </Typography>
                            </Box>
                          )}
                        </CardContent>
                      </Card>
                    </Grid>
                  ))}
                </Grid>
              </Grid>
            ))}
          </Grid>
        )}
      </Box>
    </Box>
  );
};

export default CompetitorPage;
